BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?edge ?name ?source ?target WHERE {
  ?activity vocab:NamedElement_name "Acquire%20and%20Guide" .
  ?activity vocab:Activity_edge ?edge .
  OPTIONAL { ?edge vocab:NamedElement_name ?name }
  OPTIONAL { ?edge vocab:ActivityEdge_source ?sourceNode . ?sourceNode vocab:NamedElement_name ?source }
  OPTIONAL { ?edge vocab:ActivityEdge_target ?targetNode . ?targetNode vocab:NamedElement_name ?target }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?edge ?source ?target ?guard ?guardType WHERE {
  ?activity vocab:NamedElement_name "Acquire%20and%20Guide" .
  ?activity vocab:Activity_edge ?edge .
  ?edge vocab:ActivityEdge_source ?source .
  ?source rdf:type <http://api.koneksys.com/cameo/vocab/decision%20node> .
  OPTIONAL { ?edge vocab:ActivityEdge_target ?target }
  OPTIONAL { ?edge vocab:ActivityEdge_guard ?guard . OPTIONAL { ?guard rdf:type ?guardType } }
}
LIMIT 30

BASE <http://api.koneksys.com/cameo/>
